const inputData = $('1. When Executed by Another Workflow').first().json;
const taskDataFromDB = $('2. Load Task Data').first().json;

const versions = taskDataFromDB.agent_output?.versions || [];
const sourceData = taskDataFromDB.source_data || {};
const instruction = inputData.effective_user_request || inputData.initial_prompt;
const replyToMessageId = inputData.reply_to_message_id;  // ← НОВОЕ ПОЛЕ

let sourceFileId;
let baseVersion = null;
let isNewEdit = versions.length === 0;

if (isNewEdit) {
  // Новое редактирование: используем оригинальное фото
  sourceFileId = sourceData.photo_file_id;
  baseVersion = 0;
  console.log(`[VERSION BRANCHING] New edit, using original photo (base_version: 0)`);

} else if (replyToMessageId) {
  // Reply на конкретное сообщение - ищем версию по message_id
  const targetVersion = versions.find(v => v.message_id === replyToMessageId);

  if (targetVersion) {
    // Нашли версию - используем её как базу
    sourceFileId = targetVersion.file_id;
    baseVersion = targetVersion.version;
    console.log(`[VERSION BRANCHING] Using version ${baseVersion} (message_id: ${replyToMessageId}) as base`);
  } else {
    // Не нашли - fallback на последнюю версию
    const lastVersion = versions[versions.length - 1];
    sourceFileId = lastVersion.file_id;
    baseVersion = lastVersion.version;
    console.log(`[VERSION BRANCHING] Message ${replyToMessageId} not found in versions, using latest version ${baseVersion} as fallback`);
  }

} else {
  // Нет Reply - берём последнюю версию (обычный task_update)
  const lastVersion = versions[versions.length - 1];
  sourceFileId = lastVersion.file_id;
  baseVersion = lastVersion.version;
  console.log(`[VERSION BRANCHING] No reply context, using latest version ${baseVersion}`);
}

if (!sourceFileId) {
  throw new Error('No photo_file_id found in task data');
}

return [{
  json: {
    task_id: inputData.id,
    chat_id: inputData.chat_id,
    user_id: inputData.user_id,
    file_id: sourceFileId,
    instruction: instruction,
    version: versions.length + 1,
    base_version: baseVersion,  // ← НОВОЕ: на основе какой версии создана новая
    reply_to_message_id: replyToMessageId,  // ← НОВОЕ: передаём дальше для сохранения в БД
    is_new_edit: isNewEdit
  }
}];

const telegramResponse = $input.first().json.result;
const sourceData = $('3. Determine Source Photo').item.json;
const photo = telegramResponse.photo[telegramResponse.photo.length - 1];

return [{
  json: {
    telegram_message_id: telegramResponse.message_id,
    telegram_chat_id: telegramResponse.chat.id,
    message_type: 'photo',
    task_id: sourceData.task_id,
    content_data: JSON.stringify({
      file_id: photo.file_id,
      caption: telegramResponse.caption,
      version: sourceData.version
    }),
    created_at: new Date().toISOString()
  }
}];

const telegramResponse = $input.first().json.result;
const originalTask = $('2. Load Task Data').first().json;
const sourceData = $('3. Determine Source Photo').item.json;
const enhancedPrompt = $('5. AI Prompt Enhancer with Vision').item.json.text;
const photo = telegramResponse.photo[telegramResponse.photo.length - 1];

// Получить существующие версии из оригинального task
const existingVersions = originalTask.agent_output?.versions || [];

// Создать объект новой версии
const newVersion = {
  version: sourceData.version,
  user_request: sourceData.instruction,
  file_id: photo.file_id,
  message_id: telegramResponse.message_id,
  instruction: enhancedPrompt,
  timestamp: new Date().toISOString(),
  base_version: sourceData.base_version,  // ← ДОБАВЛЕНО: на основе какой версии создана
  reply_to_message_id: sourceData.reply_to_message_id  // ← ДОБАВЛЕНО: на какое сообщение был Reply
};

// Добавить к существующим версиям
const updatedVersions = [...existingVersions, newVersion];

// Подготовить данные для UPDATE
return [{
  json: {
    task_id: originalTask.id,
    agent_output: {
      current_version: newVersion.version,
      versions: updatedVersions
    },
    status: 'completed'
  }
}];

const errorData = $input.first().json;
const taskData = $('2. Load Task Data').first().json;
const sourceData = $('3. Determine Source Photo').item.json;

// Генерируем Error ID
const errorId = `ERR-${Date.now().toString(36).toUpperCase()}`;

// Определяем откуда пришла ошибка
let errorSource = 'unknown';
let technicalError = '';
let userRequest = sourceData.instruction || 'Неизвестный запрос';

// ============================================
// ОПРЕДЕЛЯЕМ ИСТОЧНИК ОШИБКИ
// ============================================

// Проверяем есть ли node info в ошибке
const nodeName = errorData.node?.name || '';

if (nodeName.includes('Nano Banana') || errorData.error?.message?.includes('fal.run')) {
  // Ошибка от Nano Banana API
  errorSource = 'nano_banana_api';
  technicalError = errorData.error?.message || JSON.stringify(errorData);

} else if (nodeName.includes('Download') || nodeName.includes('Get File')) {
  // Ошибка при скачивании файла
  errorSource = 'download_file';
  technicalError = errorData.error?.message || JSON.stringify(errorData);

} else {
  // Неизвестная ошибка
  errorSource = 'unknown';
  technicalError = JSON.stringify(errorData);
}

// ============================================
// ФОРМИРУЕМ СООБЩЕНИЕ
// ============================================

const userMessage = `❌ Запрос "${userRequest}" не удался, попробуйте изменить запрос или изображение.`;

// ============================================
// СОЗДАЁМ ВЕРСИЮ С ОШИБКОЙ
// ============================================

const existingVersions = taskData.agent_output?.versions || [];

const errorVersion = {
  version: sourceData.version,
  user_request: userRequest,
  base_version: sourceData.base_version,
  reply_to_message_id: sourceData.reply_to_message_id,
  error: {
    error_id: errorId,
    source: errorSource,  // ← Откуда ошибка (nano_banana_api / download_file)
    message: technicalError.substring(0, 500),  // Обрезаем длинные ошибки
    timestamp: new Date().toISOString()
  }
};

const updatedVersions = [...existingVersions, errorVersion];

return [{
  json: {
    task_id: taskData.id,
    chat_id: taskData.chat_id,
    user_message: userMessage,
    agent_output: {
      current_version: sourceData.version,
      versions: updatedVersions
    },
    status: 'failed'
  }
}];
